#ifdef __cplusplus
extern "C" {
#endif

#define fp float

#define NUMBER_PAR_PER_BOX 100							

#define NUMBER_THREADS 128								

#define DOT(A,B) ((A.x)*(B.x)+(A.y)*(B.y)+(A.z)*(B.z))	

typedef struct
{
	fp x, y, z;

} THREE_VECTOR;

typedef struct
{
	fp v, x, y, z;

} FOUR_VECTOR;

typedef struct nei_str
{


	int x, y, z;
	int number;
	long offset;

} nei_str;

typedef struct box_str
{


	int x, y, z;
	int number;
	long offset;


	int nn;
	nei_str nei[26];

} box_str;

typedef struct par_str
{

	fp alpha;

} par_str;

typedef struct dim_str
{


	int cur_arg;
	int arch_arg;
	int cores_arg;
	int boxes1d_arg;


	long number_boxes;
	long box_mem;
	long space_elem;
	long space_mem;
	long space_mem2;

} dim_str;

#include <omp.h>
#include <math.h>
#include <stdio.h>
#include <sys/time.h>

static void tvsub(struct timeval *out, struct timeval *in1, struct timeval *in2)
{
	out->tv_sec = in1->tv_sec - in2->tv_sec;
	out->tv_usec = in1->tv_usec - in2->tv_usec;
	if (out->tv_usec < 0) {
		out->tv_sec--;
		out->tv_usec += 1000000;
	}
}

void kernel_cpu(	par_str d_par_gpu,
					dim_str d_dim_gpu,
					box_str *d_box_gpu,
					FOUR_VECTOR *d_rv_gpu,
					fp *d_qv_gpu,
					FOUR_VECTOR *d_fv_gpu)
{
	struct timeval tv_total_start, tv_total_end;
	struct timeval tv_init_end;
	struct timeval tv_kernel_start, tv_kernel_end;
	struct timeval tv_close_start, tv_close_end;
	float init_time = 0, kernel_time = 0, close_time = 0, total_time = 0;

	gettimeofday(&tv_total_start, NULL);

	int bx;

#pragma omp parallel for schedule(static)
	for (bx = 0; bx < d_dim_gpu.number_boxes; bx++) {

		fp a2 = 2 * d_par_gpu.alpha * d_par_gpu.alpha;

		int first_i = d_box_gpu[bx].offset;

		FOUR_VECTOR rA_shared[NUMBER_PAR_PER_BOX];
		FOUR_VECTOR rB_shared[NUMBER_PAR_PER_BOX];
		fp qB_shared[NUMBER_PAR_PER_BOX];

		// Load rA_shared
		int wtx;
		for (wtx = 0; wtx < NUMBER_PAR_PER_BOX; wtx++) {
			rA_shared[wtx] = d_rv_gpu[first_i + wtx];
		}

		int k;
		for (k = 0; k < (1 + d_box_gpu[bx].nn); k++) {

			int pointer;
			if (k == 0) {
				pointer = bx;
			} else {
				pointer = d_box_gpu[bx].nei[k - 1].number;
			}

			int first_j = d_box_gpu[pointer].offset;

			// Load rB_shared and qB_shared
			for (wtx = 0; wtx < NUMBER_PAR_PER_BOX; wtx++) {
				rB_shared[wtx] = d_rv_gpu[first_j + wtx];
				qB_shared[wtx] = d_qv_gpu[first_j + wtx];
			}

#pragma omp parallel for schedule(static)
			for (wtx = 0; wtx < NUMBER_PAR_PER_BOX; wtx++) {
				fp local_v = 0.0f;
				fp local_x = 0.0f;
				fp local_y = 0.0f;
				fp local_z = 0.0f;

				int j;
				for (j = 0; j < NUMBER_PAR_PER_BOX; j++) {
					fp r2 = rA_shared[wtx].v + rB_shared[j].v - DOT(rA_shared[wtx], rB_shared[j]);
					fp u2 = a2 * r2;
					fp vij = expf(-u2);
					fp fs = 2 * vij;
					THREE_VECTOR d;
					d.x = rA_shared[wtx].x - rB_shared[j].x;
					d.y = rA_shared[wtx].y - rB_shared[j].y;
					d.z = rA_shared[wtx].z - rB_shared[j].z;
					fp fxij = fs * d.x;
					fp fyij = fs * d.y;
					fp fzij = fs * d.z;
					local_v += qB_shared[j] * vij;
					local_x += qB_shared[j] * fxij;
					local_y += qB_shared[j] * fyij;
					local_z += qB_shared[j] * fzij;
				}

#pragma omp atomic
				d_fv_gpu[first_i + wtx].v += local_v;
#pragma omp atomic
				d_fv_gpu[first_i + wtx].x += local_x;
#pragma omp atomic
				d_fv_gpu[first_i + wtx].y += local_y;
#pragma omp atomic
				d_fv_gpu[first_i + wtx].z += local_z;
			}
		}
	}

	gettimeofday(&tv_init_end, NULL);
	tvsub(&tv_init_end, &tv_init_end, &tv_total_start);
	init_time = tv_init_end.tv_sec * 1000.0 + (float)tv_init_end.tv_usec / 1000.0;

	gettimeofday(&tv_kernel_start, NULL);
	// Kernel computation already done above
	gettimeofday(&tv_kernel_end, NULL);
	tvsub(&tv_kernel_end, &tv_kernel_end, &tv_kernel_start);
	kernel_time = tv_kernel_end.tv_sec * 1000.0 + (float)tv_kernel_end.tv_usec / 1000.0;

	gettimeofday(&tv_close_start, NULL);
	// No explicit close operations needed here
	gettimeofday(&tv_close_end, NULL);
	tvsub(&tv_close_end, &tv_close_end, &tv_close_start);
	close_time = tv_close_end.tv_sec * 1000.0 + (float)tv_close_end.tv_usec / 1000.0;

	gettimeofday(&tv_total_end, NULL);
	tvsub(&tv_total_end, &tv_total_end, &tv_total_start);
	total_time = tv_total_end.tv_sec * 1000.0 + (float)tv_total_end.tv_usec / 1000.0;

	printf("Time spent in different stages of the application:\n");
	printf("Init: %f\n", init_time);
	printf("Exec: %f\n", kernel_time);
	printf("Close: %f\n", close_time);
	printf("Total: %f\n", total_time);
}

#ifdef __cplusplus
}
#endif
